// src/components/BackupPage.jsx
import React, { useState } from 'react';
import axios from 'axios';
import NProgress from 'nprogress';
import { toast } from 'react-toastify';
import { RefreshCcw, CloudUpload, Settings, Download } from 'lucide-react';

NProgress.configure({ showSpinner: false, trickleSpeed: 120 });

const fieldLabel = 'text-sm font-medium text-gray-700';
const inputBase =
  'w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-300';

export default function BackupPage() {
  // estado manual
  const [loadingManual, setLoadingManual] = useState(false);

  // estado nuvem
  const [loadingCloud, setLoadingCloud] = useState(false);
  const [destinations, setDestinations] = useState([]); // ['gdrive','dropbox']
  const [gdriveFolderId, setGdriveFolderId] = useState('');
  const [dropboxFolder, setDropboxFolder] = useState('/Backups');
  const [cleanupDays, setCleanupDays] = useState(30);
  const [lastResult, setLastResult] = useState(null);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}` };

  function toggleDestination(key) {
    setDestinations((prev) =>
      prev.includes(key) ? prev.filter((d) => d !== key) : [...prev, key]
    );
  }

  async function handleManualDownload() {
    try {
      setLoadingManual(true);
      NProgress.start();

      const res = await axios.post('/api/backup/manual', null, {
        headers,
        responseType: 'blob',
      });

      const blob = new Blob([res.data], { type: 'application/zip' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      const now = new Date()
        .toISOString()
        .replace(/[:.]/g, '-')
        .replace('T', '_')
        .slice(0, 19);
      a.href = url;
      a.download = `backup_poliub_${now}.zip`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Backup gerado com sucesso!');
    } catch (err) {
      // tenta extrair a razão vinda do backend
      try {
        const text = await err?.response?.data?.text?.();
        const parsed = text && JSON.parse(text);
        toast.error(parsed?.reason || 'Falha ao gerar backup.');
      } catch {
        toast.error('Falha ao gerar backup.');
      }
    } finally {
      NProgress.done();
      setLoadingManual(false);
    }
  }

  async function handleCloudBackup() {
    if (destinations.length === 0) {
      toast.warn('Selecione pelo menos um destino (Google Drive ou Dropbox).');
      return;
    }
    // validações condicionais
    if (destinations.includes('gdrive') && !gdriveFolderId.trim()) {
      toast.warn('Informe o ID da pasta no Google Drive.');
      return;
    }

    try {
      setLoadingCloud(true);
      NProgress.start();
      const body = {
        destinations,
        cleanupDays: Number(cleanupDays) || 30,
        gdriveFolderId: gdriveFolderId || undefined,
        dropboxFolder: dropboxFolder || '/Backups',
      };

      const { data } = await axios.post('/api/backup/run', body, { headers });
      setLastResult(data);
      toast.success('Backup enviado para a nuvem!');
    } catch (err) {
      try {
        const reason = err?.response?.data?.reason || err?.message;
        toast.error(reason || 'Falha no backup para nuvem.');
      } catch {
        toast.error('Falha no backup para nuvem.');
      }
    } finally {
      NProgress.done();
      setLoadingCloud(false);
    }
  }

  return (
    <div className="max-w-5xl mx-auto px-4 py-6">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-semibold text-gray-800">Backup</h2>
        <span className="inline-flex items-center gap-2 text-sm text-gray-500">
          <Settings size={16} /> Configurações
        </span>
      </div>

      {/* CARD: Backup Manual (download .zip) */}
      <div className="bg-white rounded-2xl shadow p-6 mb-6">
        <h3 className="text-lg font-semibold text-gray-800 mb-2">
          Backup manual (download .zip)
        </h3>
        <p className="text-sm text-gray-600 mb-4">
          Gera um dump do banco atual e baixa um arquivo .zip com o .sql dentro.
        </p>

        <button
          onClick={handleManualDownload}
          disabled={loadingManual}
          className={`${
            loadingManual ? 'opacity-70 cursor-not-allowed' : ''
          } bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold px-4 py-2 rounded-full inline-flex items-center gap-2`}
        >
          {loadingManual ? (
            <span className="inline-block h-4 w-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
          ) : (
            <Download size={18} />
          )}
          {loadingManual ? 'Gerando...' : 'Fazer backup agora'}
        </button>
      </div>

      {/* CARD: Backup para a Nuvem */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h3 className="text-lg font-semibold text-gray-800 mb-2">
          Backup para a nuvem (Google Drive / Dropbox)
        </h3>
        <p className="text-sm text-gray-600 mb-4">
          Envia o backup para a(s) nuvem(ns) selecionada(s) e remove backups mais antigos que o
          período escolhido.
        </p>

        {/* Destinos */}
        <div className="mb-4 grid grid-cols-1 md:grid-cols-2 gap-4">
          <label className="flex items-center gap-3 p-3 rounded-lg border hover:bg-gray-50 cursor-pointer">
            <input
              type="checkbox"
              checked={destinations.includes('gdrive')}
              onChange={() => toggleDestination('gdrive')}
            />
            <span>Google Drive</span>
          </label>
          <label className="flex items-center gap-3 p-3 rounded-lg border hover:bg-gray-50 cursor-pointer">
            <input
              type="checkbox"
              checked={destinations.includes('dropbox')}
              onChange={() => toggleDestination('dropbox')}
            />
            <span>Dropbox</span>
          </label>
        </div>

        {/* Campos condicionais */}
        {destinations.includes('gdrive') && (
          <div className="mb-4">
            <label className={fieldLabel}>ID da pasta no Google Drive</label>
            <input
              type="text"
              className={inputBase}
              placeholder="Ex.: 1AbCDefGhijkLMNOPqR..."
              value={gdriveFolderId}
              onChange={(e) => setGdriveFolderId(e.target.value)}
            />
            <p className="text-xs text-gray-500 mt-1">
              Dica: Compartilhe a pasta com o e-mail da Service Account.
            </p>
          </div>
        )}

        {destinations.includes('dropbox') && (
          <div className="mb-4">
            <label className={fieldLabel}>Pasta no Dropbox</label>
            <input
              type="text"
              className={inputBase}
              placeholder="/Backups"
              value={dropboxFolder}
              onChange={(e) => setDropboxFolder(e.target.value)}
            />
          </div>
        )}

        {/* Retenção */}
        <div className="mb-6 max-w-xs">
          <label className={fieldLabel}>Excluir backups com mais de (dias)</label>
          <input
            type="number"
            min={1}
            className={inputBase}
            value={cleanupDays}
            onChange={(e) => setCleanupDays(e.target.value)}
          />
        </div>

        <button
          onClick={handleCloudBackup}
          disabled={loadingCloud}
          className={`${
            loadingCloud ? 'opacity-70 cursor-not-allowed' : ''
          } bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full inline-flex items-center gap-2`}
        >
          {loadingCloud ? (
            <span className="inline-block h-4 w-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
          ) : (
            <CloudUpload size={18} />
          )}
          {loadingCloud ? 'Enviando...' : 'Enviar para a nuvem'}
        </button>

        {/* Resultado (debug amigável) */}
        {lastResult && (
          <div className="mt-6 bg-gray-50 border rounded-lg p-4 text-sm overflow-x-auto">
            <pre className="whitespace-pre-wrap break-all">
              {JSON.stringify(lastResult, null, 2)}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
}
